#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int checkPath(char **grid, int n, int x, int y) {
    int dx[] = {1, 0};
    int dy[] = {0, 1};
    for (int i = 0; i < 2; i++) {
        int currX = x;
        int currY = y;
        while (currX >= 0 && currX < n && currY >= 0 && currY < n) {
            if (grid[currX][currY] == '#') return 0;
            currX += dx[i];
            currY += dy[i];
        }
    }
    return 1;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        char **grid = (char **)malloc(n * sizeof(char *));
        for (int i = 0; i < n; i++) {
            grid[i] = (char *)malloc((n + 1) * sizeof(char));
            scanf("%s", grid[i]);
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] == '.' && checkPath(grid, n, i, j)) count++;
            }
        }
        printf("%d\n", count);
        for (int i = 0; i < n; i++) free(grid[i]);
        free(grid);
    }
    return 0;
}

