import java.util.Scanner;
public class Main {
    public static int checkPath(String[] grid, int n, int x, int y) {
        int dx[] = {1, 0};
        int dy[] = {0, 1};
        for (int i = 0; i < 2; i++) {
            int currX = x;
            int currY = y;
            while (currX >= 0 && currX < n && currY >= 0 && currY < n) {
                if (grid[currX].charAt(currY) == '#') return 0;
                currX += dx[i];
                currY += dy[i];
            }
        }
        return 1;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            String[] grid = new String[n];
            for (int i = 0; i < n; i++) grid[i] = sc.next();
            int count = 0;
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    if (grid[i].charAt(j) == '.' && checkPath(grid, n, i, j) == 1) count++;
                }
            }
            System.out.println(count);
        }
    }
}

